#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LogLevel {
    Info,
    Warn,
    Error,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LogEvent {
    pub event_name: String,
    pub level: LogLevel,
}

// Continue from the previous lesson.
// TODO: define LogFields and LogEvent with structured fields.

use rust_daily_lesson::{LogEvent, LogFields, LogLevel};

#[test]
fn event_carries_structured_fields() {
    let event = LogEvent {
        event_name: "request.retry".to_owned(),
        level: LogLevel::Warn,
        fields: LogFields { request_id: "req-1".to_owned(), user_id: Some("user-1".to_owned()), attempt: 2 },
    };

    assert_eq!(event.fields.request_id, "req-1");
    assert_eq!(event.fields.attempt, 2);
}

